<div class="card border-0 shadow-sm"><div class="card-header bg-white d-flex justify-content-between align-items-center"><strong>Gallery Images</strong><a class="btn btn-primary-brand btn-sm" href="<?php echo e(route('admin.gallery-images.create')); ?>">Add New</a></div><div class="card-body"><form class="row g-2"><div class="col-md-4"><input class="form-control" name="search" value="<?php echo e(request('search')); ?>" placeholder="Search title or category"></div><div class="col-md-3"><select class="form-select" name="category"><option value="">All categories</option><?php $__currentLoopData = $categories; $__env->addLoop($__currentLoopData); foreach($__currentLoopData as $category): $__env->incrementLoopIndices(); $loop = $__env->getLastLoop(); ?><option value="<?php echo e($category); ?>" <?php if($category===request('category')): echo 'selected'; endif; ?>><?php echo e($category); ?></option><?php endforeach; $__env->popLoop(); $loop = $__env->getLastLoop(); ?></select></div><div class="col-md-2"><select class="form-select" name="status"><option value="">All statuses</option><option value="1" <?php if(request('status')==='1'): echo 'selected'; endif; ?>>Active</option><option value="0" <?php if(request('status')==='0'): echo 'selected'; endif; ?>>Inactive</option></select></div><div class="col-md-3"><button class="btn btn-outline-primary-brand">Filter</button><a class="btn btn-outline-secondary" href="<?php echo e(route('admin.gallery-images.index')); ?>">Reset</a></div></form></div><div class="table-responsive"><table class="table align-middle mb-0"><thead><tr><th>Title</th><th>Image</th><th>Category</th><th>Sort</th><th>Status</th><th class="text-end">Actions</th></tr></thead><tbody><?php $__empty_1 = true; $__currentLoopData = $items; $__env->addLoop($__currentLoopData); foreach($__currentLoopData as $item): $__env->incrementLoopIndices(); $loop = $__env->getLastLoop(); $__empty_1 = false; ?><tr><td><?php echo e($item->title ?? '—'); ?></td><td><img src="<?php echo e(Storage::url($item->image)); ?>" style="width:80px;height:48px;object-fit:cover" class="rounded" alt=""></td><td><?php echo e($item->category ?? '—'); ?></td><td><?php echo e($item->sort_order); ?></td><td><span class="badge <?php echo e($item->status ? 'text-bg-success' : 'text-bg-secondary'); ?>"><?php echo e($item->status ? 'Active' : 'Inactive'); ?></span></td><td class="text-end"><a class="btn btn-sm btn-outline-primary-brand" href="<?php echo e(route('admin.gallery-images.edit',$item)); ?>">Edit</a><form class="d-inline" method="POST" action="<?php echo e(route('admin.gallery-images.destroy',$item)); ?>" onsubmit="return confirm('Delete this gallery image?')"><?php echo csrf_field(); ?> <?php echo method_field('DELETE'); ?><button class="btn btn-sm btn-outline-danger">Delete</button></form></td></tr><?php endforeach; $__env->popLoop(); $loop = $__env->getLastLoop(); if ($__empty_1): ?><tr><td colspan="6" class="text-center text-muted py-4">No gallery images found.</td></tr><?php endif; ?></tbody></table></div><div class="card-footer bg-white"><?php echo e($items->links()); ?></div></div>
